Firebase Auth is available for login/signup features.

**Import:** `import { useAuth } from '../hooks/useAuth';`

**Usage:**
```tsx
const { user, signIn, signUp, signOut, isAuthenticated, loading, error } = useAuth();

// Sign up
await signUp(email, password, displayName?);

// Sign in
await signIn(email, password);

// Sign out
await signOut();

// Check auth state
if (isAuthenticated) { /* user is logged in */ }
```

**NEVER use browser prompt() for credentials - build a proper form.**

File uploads are available via System Storage.

**Import:** `import { useSystemStorage } from '../hooks/useSystemStorage';`

**Usage:**
```tsx
const { upload, uploading, error } = useSystemStorage();

const handleUpload = async (file: File) => {
  const result = await upload(file);
  if (result) {
    console.log('Uploaded URL:', result.url);
  }
};
```

**For file inputs:**
```tsx
<input
  type="file"
  onChange={(e) => e.target.files?.[0] && handleUpload(e.target.files[0])}
  disabled={uploading}
/>
```

**File uploads available but database is NOT.**

You CAN:
- Upload files using useSystemStorage
- Display uploaded files

You CANNOT:
- Persist any data (no Firestore)
- User authentication

**For features without database:**
- Use React state for data (lost on refresh)
- Explain data won't persist

```tsx
const [items, setItems] = useState([]);
const { upload } = useSystemStorage();

const handleUpload = async (file: File) => {
  const result = await upload(file);
  if (result?.url) {
    setItems([...items, { image: result.url }]); // Temporary
  }
};
```

**Tell the user:** "Files can be uploaded, but data won't persist after refresh. Enable Firebase for data storage."

**Full CRUD Example with useFirestore:**
```tsx
import { useState } from 'react';
import { useFirestore } from '../hooks/useFirestore';
import { Button } from '../components/ui/button';
import { Input } from '../components/ui/input';
import { Card } from '../components/ui/card';
import { toast } from 'sonner';

interface Review {
  title: string;
  author: string;
  rating: number;
  content: string;
  createdAt: Date;
}

export default function ReviewManager() {
  const { documents: reviews, loading, add, remove } = useFirestore<Review>('reviews');
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    await add({
      title,
      author: 'Anonymous',
      rating: 5,
      content,
      createdAt: new Date(),
    });
    setTitle('');
    setContent('');
    toast.success('Review added!');  // NOT alert()!
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div>
      <form onSubmit={handleSubmit}>
        <Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Title" />
        <Input value={content} onChange={(e) => setContent(e.target.value)} placeholder="Review" />
        <Button type="submit">Add Review</Button>
      </form>
      {reviews.map((review) => (
        <Card key={review.id}>
          <h3>{review.title}</h3>
          <p>{review.content}</p>
          <Button variant="destructive" onClick={() => remove(review.id)}>Delete</Button>
        </Card>
      ))}
    </div>
  );
}
```

**Key points:**
- Real-time sync (no manual refresh needed)
- Use `toast.success()` instead of `alert()`
- TypeScript interface matches Firestore document
